+        {
+          for (size_t j = 0; j < POSE_SIZE; j++)
+          {
+            covarianceRotated(i, j) = (updateVector[i] && updateVector[j] ? msg->pose.covariance[POSE_SIZE * i + j] : 0.0);
+          }
+        }
